<?php
require __DIR__.'/../includes/bootstrap.php';require_auth();
if(!booth_management_ready())redirect('upgrade-booth-management.php');
$id=(int)($_GET['id']??$_POST['booth_id']??0);$tab=$_GET['tab']??$_POST['tab']??'overview';
$s=db()->prepare('SELECT * FROM booths WHERE id=?');$s->execute([$id]);$booth=$s->fetch();if(!$booth||!can_manage_booth($booth)){http_response_code(403);exit('Booth access required.');}
$me=user();$isOwner=(int)$booth['owner_user_id']===(int)$me['id']||$me['role']==='admin';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$a=$_POST['action']??'';try{
 if($a==='save_profile'){db()->prepare('UPDATE booths SET name=?,tagline=?,description=?,website=?,contact_email=?,support_email=?,booth_presence=?,location_label=?,hours_text=?,instagram_url=?,youtube_url=?,tiktok_url=?,discord_url=? WHERE id=?')->execute([trim($_POST['name']),trim($_POST['tagline']),trim($_POST['description']),trim($_POST['website']),trim($_POST['contact_email']),trim($_POST['support_email']),$_POST['booth_presence'],trim($_POST['location_label']),trim($_POST['hours_text']),trim($_POST['instagram_url']),trim($_POST['youtube_url']),trim($_POST['tiktok_url']),trim($_POST['discord_url']),$id]);$logo=save_booth_image('logo','logos',$id);$banner=save_booth_image('banner','banners',$id);if($logo||$banner)db()->prepare('UPDATE booths SET logo_path=COALESCE(?,logo_path),banner_path=COALESCE(?,banner_path) WHERE id=?')->execute([$logo,$banner,$id]);flash('success','Booth profile updated.');}
 if($a==='save_settings'){db()->prepare('UPDATE booths SET commerce_mode=?,external_store_url=?,return_policy=?,shipping_policy=? WHERE id=?')->execute([$_POST['commerce_mode'],trim($_POST['external_store_url']),trim($_POST['return_policy']),trim($_POST['shipping_policy']),$id]);flash('success','Booth settings updated.');}
 if($a==='add_product'){$name=trim($_POST['product_name']??'');if($name==='')throw new RuntimeException('Product name is required.');$inv=$_POST['inventory_quantity']===''?null:max(0,(int)$_POST['inventory_quantity']);db()->prepare("INSERT INTO booth_products(booth_id,name,slug,description,product_type,price,compare_at_price,sku,inventory_quantity,shipping_note,download_note,convention_exclusive,signed_item,preorder,is_featured,status) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)")->execute([$id,$name,product_slug($name,$id),trim($_POST['product_description']),$_POST['product_type'],(float)$_POST['price'],$_POST['compare_at_price']===''?null:(float)$_POST['compare_at_price'],trim($_POST['sku']),$inv,trim($_POST['shipping_note']),trim($_POST['download_note']),isset($_POST['convention_exclusive']),isset($_POST['signed_item']),isset($_POST['preorder']),isset($_POST['is_featured']),$_POST['product_status']]);$pid=(int)db()->lastInsertId();$img=save_booth_image('product_image','products',$pid);if($img)db()->prepare('UPDATE booth_products SET image_path=? WHERE id=?')->execute([$img,$pid]);flash('success','Product added.');}
 if($a==='update_product'){$pid=(int)$_POST['product_id'];db()->prepare('UPDATE booth_products SET name=?,description=?,product_type=?,price=?,compare_at_price=?,sku=?,inventory_quantity=?,shipping_note=?,download_note=?,convention_exclusive=?,signed_item=?,preorder=?,is_featured=?,status=? WHERE id=? AND booth_id=?')->execute([trim($_POST['product_name']),trim($_POST['product_description']),$_POST['product_type'],(float)$_POST['price'],$_POST['compare_at_price']===''?null:(float)$_POST['compare_at_price'],trim($_POST['sku']),$_POST['inventory_quantity']===''?null:max(0,(int)$_POST['inventory_quantity']),trim($_POST['shipping_note']),trim($_POST['download_note']),isset($_POST['convention_exclusive']),isset($_POST['signed_item']),isset($_POST['preorder']),isset($_POST['is_featured']),$_POST['product_status'],$pid,$id]);$img=save_booth_image('product_image','products',$pid);if($img)db()->prepare('UPDATE booth_products SET image_path=? WHERE id=? AND booth_id=?')->execute([$img,$pid,$id]);flash('success','Product updated.');}
 if($a==='archive_product'){db()->prepare("UPDATE booth_products SET status='archived' WHERE id=? AND booth_id=?")->execute([(int)$_POST['product_id'],$id]);flash('success','Product archived.');}
 if($a==='order_status'){db()->prepare('UPDATE booth_orders SET order_status=?,payment_status=? WHERE id=? AND booth_id=?')->execute([$_POST['order_status'],$_POST['payment_status'],(int)$_POST['order_id'],$id]);flash('success','Order updated.');}
 if($a==='add_team'&&$isOwner){$email=trim($_POST['email']);$q=db()->prepare('SELECT id FROM users WHERE email=? LIMIT 1');$q->execute([$email]);$uid=(int)$q->fetchColumn();if(!$uid)throw new RuntimeException('No registered user has that email address.');if($uid===(int)$booth['owner_user_id'])throw new RuntimeException('The booth owner already has full access.');db()->prepare("INSERT INTO booth_team_members(booth_id,user_id,role,status) VALUES(?,?,?,'active') ON DUPLICATE KEY UPDATE role=VALUES(role),status='active'")->execute([$id,$uid,$_POST['role']]);flash('success','Team member added.');}
 if($a==='remove_team'&&$isOwner){db()->prepare("UPDATE booth_team_members SET status='inactive' WHERE id=? AND booth_id=?")->execute([(int)$_POST['team_id'],$id]);flash('success','Team member removed.');}
 if($a==='add_gallery'){$path=save_booth_image('gallery_image','gallery',$id);if(!$path)throw new RuntimeException('Choose an image.');db()->prepare('INSERT INTO booth_gallery(booth_id,image_path,caption,sort_order) VALUES(?,?,?,?)')->execute([$id,$path,trim($_POST['caption']),max(0,(int)$_POST['sort_order'])]);flash('success','Gallery image added.');}
 if($a==='delete_gallery'){db()->prepare('DELETE FROM booth_gallery WHERE id=? AND booth_id=?')->execute([(int)$_POST['gallery_id'],$id]);flash('success','Gallery image removed.');}
 if($a==='add_download'){$file=save_booth_file('download_file','downloads',$id);$url=trim($_POST['external_url']);if(!$file&&$url==='')throw new RuntimeException('Upload a file or enter an external URL.');db()->prepare('INSERT INTO booth_downloads(booth_id,title,description,file_path,external_url,is_public) VALUES(?,?,?,?,?,?)')->execute([$id,trim($_POST['title']),trim($_POST['description']),$file,$url,isset($_POST['is_public'])]);flash('success','Download added.');}
 if($a==='delete_download'){db()->prepare('DELETE FROM booth_downloads WHERE id=? AND booth_id=?')->execute([(int)$_POST['download_id'],$id]);flash('success','Download removed.');}
 redirect_booth_manage($id,$tab);
 }catch(Throwable $e){flash('error',$e->getMessage());redirect_booth_manage($id,$tab);}}
$products=db()->prepare('SELECT * FROM booth_products WHERE booth_id=? ORDER BY created_at DESC');$products->execute([$id]);$products=$products->fetchAll();
$orders=db()->prepare('SELECT * FROM booth_orders WHERE booth_id=? ORDER BY created_at DESC');$orders->execute([$id]);$orders=$orders->fetchAll();
$team=db()->prepare('SELECT tm.*,u.display_name,u.email FROM booth_team_members tm JOIN users u ON u.id=tm.user_id WHERE tm.booth_id=? AND tm.status="active" ORDER BY tm.role,u.display_name');$team->execute([$id]);$team=$team->fetchAll();
$gallery=db()->prepare('SELECT * FROM booth_gallery WHERE booth_id=? ORDER BY sort_order,created_at');$gallery->execute([$id]);$gallery=$gallery->fetchAll();
$downloads=db()->prepare('SELECT * FROM booth_downloads WHERE booth_id=? ORDER BY created_at DESC');$downloads->execute([$id]);$downloads=$downloads->fetchAll();
$stats=db()->prepare("SELECT (SELECT COUNT(*) FROM booth_views WHERE booth_id=?) views,(SELECT COUNT(*) FROM booth_orders WHERE booth_id=?) orders,(SELECT COALESCE(SUM(total),0) FROM booth_orders WHERE booth_id=? AND order_status<>'cancelled') revenue,(SELECT COUNT(*) FROM booth_products WHERE booth_id=? AND status='active') active_products");$stats->execute([$id,$id,$id,$id]);$stats=$stats->fetch();
app_header('Manage '.$booth['name']);
?>
<section class="dashboard-hero"><p class="eyebrow">BOOTH MANAGEMENT</p><h1><?=e($booth['name'])?></h1><p><span class="status-badge <?=e($booth['status'])?>"><?=e(ucfirst($booth['status']))?></span> · <?=e(ucfirst($booth['booth_presence']))?><?php if($booth['status']==='approved'):?> · <a href="view.php?slug=<?=urlencode($booth['slug'])?>">View public booth</a><?php endif?></p></section>
<nav class="booth-tabs"><?php foreach(['overview'=>'Overview','profile'=>'Profile','products'=>'Products','orders'=>'Orders','team'=>'Team','media'=>'Gallery & Downloads','settings'=>'Settings'] as $key=>$label):?><a class="<?=$tab===$key?'active':''?>" href="manage.php?id=<?=$id?>&tab=<?=$key?>"><?=e($label)?></a><?php endforeach?></nav>
<?php if($tab==='overview'):?><section class="stat-card-grid"><article class="app-card"><strong><?=$stats['views']?></strong><span>Unique daily views</span></article><article class="app-card"><strong><?=$stats['active_products']?></strong><span>Active products</span></article><article class="app-card"><strong><?=$stats['orders']?></strong><span>Total orders</span></article><article class="app-card"><strong>$<?=number_format((float)$stats['revenue'],2)?></strong><span>Demo order value</span></article></section><section class="management-layout"><div class="app-card"><h2>Booth checklist</h2><ul class="checklist"><li class="<?=$booth['logo_path']?'done':''?>">Upload a logo</li><li class="<?=$booth['banner_path']?'done':''?>">Upload a banner</li><li class="<?=$booth['description']?'done':''?>">Write a booth description</li><li class="<?=count($products)?'done':''?>">Add at least one product</li><li class="<?=count($gallery)?'done':''?>">Add gallery media</li><li class="<?=$booth['hours_text']?'done':''?>">Set booth hours</li></ul></div><aside><section class="app-card"><h2>Quick actions</h2><p><a class="button primary" href="manage.php?id=<?=$id?>&tab=products">Add product</a></p><p><a class="button ghost" href="manage.php?id=<?=$id?>&tab=media">Add media</a></p></section></aside></section>
<?php elseif($tab==='profile'):?><section class="form-card"><h2>Public Booth Profile</h2><form method="post" enctype="multipart/form-data" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="save_profile"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="profile"><label>Name<input name="name" value="<?=e($booth['name'])?>" required></label><label>Tagline<input name="tagline" value="<?=e($booth['tagline'])?>"></label><label class="full">Description<textarea name="description" rows="6"><?=e($booth['description'])?></textarea></label><label>Presence<select name="booth_presence"><?php foreach(['open','away','offline'] as $v):?><option <?=$booth['booth_presence']===$v?'selected':''?> value="<?=$v?>"><?=ucfirst($v)?></option><?php endforeach?></select></label><label>Location / Hall<input name="location_label" value="<?=e($booth['location_label'])?>" placeholder="Artist Alley, Table A12"></label><label class="full">Hours<textarea name="hours_text" rows="3" placeholder="Mon–Fri 10am–6pm ET"><?=e($booth['hours_text'])?></textarea></label><label>Website<input type="url" name="website" value="<?=e($booth['website'])?>"></label><label>Public contact email<input type="email" name="contact_email" value="<?=e($booth['contact_email'])?>"></label><label>Support email<input type="email" name="support_email" value="<?=e($booth['support_email'])?>"></label><label>Instagram<input type="url" name="instagram_url" value="<?=e($booth['instagram_url'])?>"></label><label>YouTube<input type="url" name="youtube_url" value="<?=e($booth['youtube_url'])?>"></label><label>TikTok<input type="url" name="tiktok_url" value="<?=e($booth['tiktok_url'])?>"></label><label>Discord<input type="url" name="discord_url" value="<?=e($booth['discord_url'])?>"></label><label>Logo<input type="file" name="logo" accept="image/*"></label><label>Banner<input type="file" name="banner" accept="image/*"></label><div class="full"><button class="button primary">Save Profile</button></div></form></section>
<?php elseif($tab==='products'):?><section class="management-layout"><div><section class="form-card"><h2>Add Product</h2><form method="post" enctype="multipart/form-data" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="add_product"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="products"><?php include __DIR__.'/product-fields.php';?><div class="full"><button class="button primary">Add Product</button></div></form></section></div><aside><section class="app-card"><h2>Product Catalog</h2><?php foreach($products as $p):?><details class="manage-product"><summary><strong><?=e($p['name'])?></strong><span>$<?=number_format((float)$p['price'],2)?> · <?=e($p['status'])?></span></summary><form method="post" enctype="multipart/form-data" class="form-grid compact"><?=csrf_field()?><input type="hidden" name="action" value="update_product"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="products"><input type="hidden" name="product_id" value="<?=$p['id']?>"><?php $editProduct=$p;include __DIR__.'/product-fields.php';unset($editProduct);?><button class="button primary full">Save Product</button></form><form method="post" onsubmit="return confirm('Archive this product?')"><?=csrf_field()?><input type="hidden" name="action" value="archive_product"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="products"><input type="hidden" name="product_id" value="<?=$p['id']?>"><button class="text-link danger">Archive</button></form></details><?php endforeach?><?php if(!$products):?><p class="muted">No products yet.</p><?php endif?></section></aside></section>
<?php elseif($tab==='orders'):?><section class="app-card"><h2>Orders</h2><?php foreach($orders as $o):$it=db()->prepare('SELECT * FROM booth_order_items WHERE order_id=?');$it->execute([$o['id']]);?><details class="order-card"><summary><strong><?=e($o['order_number'])?></strong><span><?=e($o['customer_name'])?> · $<?=number_format((float)$o['total'],2)?> · <?=e($o['order_status'])?></span></summary><p><strong>Email:</strong> <?=e($o['customer_email'])?></p><p><strong>Ship to:</strong> <?=e(trim($o['shipping_address1'].' '.$o['shipping_address2'].', '.$o['shipping_city'].', '.$o['shipping_state'].' '.$o['shipping_postal'].' '.$o['shipping_country'],', '))?></p><ul><?php foreach($it->fetchAll() as $x):?><li><?=e($x['product_name'])?> × <?=$x['quantity']?> — $<?=number_format((float)$x['line_total'],2)?></li><?php endforeach?></ul><form method="post" class="inline-admin-form"><?=csrf_field()?><input type="hidden" name="action" value="order_status"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="orders"><input type="hidden" name="order_id" value="<?=$o['id']?>"><select name="order_status"><?php foreach(['pending','confirmed','processing','shipped','completed','cancelled'] as $v):?><option <?=$o['order_status']===$v?'selected':''?>><?=$v?></option><?php endforeach?></select><select name="payment_status"><?php foreach(['not_required','pending','paid','failed','refunded'] as $v):?><option <?=$o['payment_status']===$v?'selected':''?>><?=$v?></option><?php endforeach?></select><button class="button primary">Update</button></form></details><?php endforeach?><?php if(!$orders):?><p class="muted">No orders yet.</p><?php endif?></section>
