<?php elseif($tab==='media'):?><section class="management-layout"><div><section class="form-card"><h2>Add Gallery Image</h2><form method="post" enctype="multipart/form-data" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="add_gallery"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="media"><label>Image<input type="file" name="gallery_image" accept="image/*" required></label><label>Caption<input name="caption"></label><label>Sort order<input type="number" name="sort_order" value="0"></label><div class="full"><button class="button primary">Add Image</button></div></form></section><section class="form-card"><h2>Add Download</h2><form method="post" enctype="multipart/form-data" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="add_download"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="media"><label>Title<input name="title" required></label><label>File<input type="file" name="download_file"></label><label class="full">External URL<input type="url" name="external_url"></label><label class="full">Description<textarea name="description"></textarea></label><label><input type="checkbox" name="is_public" checked> Public</label><div class="full"><button class="button primary">Add Download</button></div></form></section></div><aside><section class="app-card"><h2>Gallery</h2><div class="mini-gallery"><?php foreach($gallery as $g):?><div><img src="<?=e(base_url($g['image_path']))?>" alt=""><span><?=e($g['caption'])?></span><form method="post"><?=csrf_field()?><input type="hidden" name="action" value="delete_gallery"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="media"><input type="hidden" name="gallery_id" value="<?=$g['id']?>"><button class="text-link danger">Remove</button></form></div><?php endforeach?></div><h2>Downloads</h2><?php foreach($downloads as $d):?><div class="manage-list-item"><strong><?=e($d['title'])?></strong><span><?=$d['is_public']?'Public':'Private'?></span><form method="post"><?=csrf_field()?><input type="hidden" name="action" value="delete_download"><input type="hidden" name="booth_id" value="<?=$id?>"><input type="hidden" name="tab" value="media"><input type="hidden" name="download_id" value="<?=$d['id']?>"><button class="text-link danger">Remove</button></form></div><?php endforeach?></section></aside></section>
